import{_ as e,c as l,o as r,a6 as o}from"./chunks/framework.D3k0dqWr.js";const u=JSON.parse('{"title":"下载安装","description":"","frontmatter":{},"headers":[],"relativePath":"Docs/Knowledge/Tools/Blender/DownloadAndInstall.md","filePath":"Docs/Knowledge/Tools/Blender/DownloadAndInstall.md","lastUpdated":1758515042000}'),t={name:"Docs/Knowledge/Tools/Blender/DownloadAndInstall.md"};function n(i,a,d,h,s,c){return r(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="下载安装" tabindex="-1">下载安装 <a class="header-anchor" href="#下载安装" aria-label="Permalink to &quot;下载安装&quot;">​</a></h1><h2 id="官网下载" tabindex="-1">官网下载 <a class="header-anchor" href="#官网下载" aria-label="Permalink to &quot;官网下载&quot;">​</a></h2><h3 id="下载安装包" tabindex="-1">下载安装包 <a class="header-anchor" href="#下载安装包" aria-label="Permalink to &quot;下载安装包&quot;">​</a></h3><p>访问 <a href="https://www.blender.org/download/" target="_blank" rel="noreferrer">Blender官网</a></p><p>官网会自动检测你的操作系统并推荐合适的版本, 直接点击蓝色下载按钮即可.</p><p>如果你的操作系统不是浏览器识别的, 可以点击下载其他版本.</p><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><p>运行安装包, 同意一个协议, 然后选择安装路径, 点击安装即可.</p><p>很快的.</p><h2 id="steam" tabindex="-1">Steam <a class="header-anchor" href="#steam" aria-label="Permalink to &quot;Steam&quot;">​</a></h2><p>在 Steam 中搜索 Blender, 找到并添加到库中.</p><p>安装后可以直接在 Steam 库中运行 Blender.</p><h2 id="第一次运行" tabindex="-1">第一次运行 <a class="header-anchor" href="#第一次运行" aria-label="Permalink to &quot;第一次运行&quot;">​</a></h2><p>第一次运行 Blender 时, 你会看到一个欢迎界面.</p><p>选择语言, 快捷方式等设置就可以了, 一般选择语言就可以了</p><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>电脑可以下载安装多个版本的 Blender, 他们互不冲突.</li><li>第一次初始化时, 如果电脑有其他版本的 Blender, 可以选择导入设置.</li><li>如果觉得界面太小, 可以在 编辑 -&gt; 偏好设置 -&gt; 界面 中调整分辨率缩放, 一般 <code>1.1</code> 就差不多了.</li></ul><h2 id="最低系统要求" tabindex="-1">最低系统要求 <a class="header-anchor" href="#最低系统要求" aria-label="Permalink to &quot;最低系统要求&quot;">​</a></h2><ul><li>支持 SSE2 的 64 位四核CPU</li><li>8 GB RAM</li><li>2 GB RAM, 支持 OpenGL 4.3的显卡</li></ul><h3 id="我的电脑配置" tabindex="-1">我的电脑配置 <a class="header-anchor" href="#我的电脑配置" aria-label="Permalink to &quot;我的电脑配置&quot;">​</a></h3><ul><li>CPU: Intel Core i7-10875H</li><li>内存: 32GB DDR4</li><li>显卡: NVIDIA GeForce RTX 2060 6GB</li><li>系统: Windows 10</li></ul><h3 id="你的电脑配置" tabindex="-1">你的电脑配置 <a class="header-anchor" href="#你的电脑配置" aria-label="Permalink to &quot;你的电脑配置&quot;">​</a></h3><p>我怎么会知道?</p><p>请打开你的任务管理器, 点击性能, 可以看到你的 CPU, 内存, 显卡等信息.</p>',24)])])}const m=e(t,[["render",n]]);export{u as __pageData,m as default};
